<div class="page-head forms-page-head"><div><p class="eyebrow">Збір даних</p><h1>Форми</h1><p class="page-subtitle">Створюйте опитування й реєстрації та переглядайте відповіді в одному місці.</p></div><div class="form-actions"><a class="button secondary" href="<?= url('/admin/forms/submissions') ?>"><span class="mdi mdi-inbox-outline"></span><span>Усі відповіді</span></a><a class="button" href="<?= url('/admin/forms/edit') ?>"><span class="mdi mdi-plus"></span><span>Створити форму</span></a></div></div>
<div class="metrics"><div class="metric"><div><span>Усього форм</span><strong><?= count($items) ?></strong></div><span class="mdi mdi-form-select metric-icon"></span></div><div class="metric"><div><span>Опубліковано</span><strong><?= $published ?></strong></div><span class="mdi mdi-check-circle-outline metric-icon"></span></div><div class="metric"><div><span>Отримано відповідей</span><strong><?= $totalAnswers ?></strong></div><span class="mdi mdi-message-text-outline metric-icon"></span></div></div>
<div class="list-panel"><div class="table-scroll"><table><thead><tr><th>Форма</th><th>Тип</th><th>Статус</th><th>Відповіді</th><th>Остання відповідь</th><th></th></tr></thead><tbody>
<?php foreach ($items as $item): ?><tr><td><div class="forms-list-title"><span class="forms-list-icon mdi mdi-form-textbox"></span><div><strong><?= e($item['title']) ?></strong><div class="meta">ID <?= e((string)$item['id']) ?> · <?= e($item['slug']) ?></div></div></div></td><td><?= e($typeLabels[$item['type']]??$item['type']) ?></td><td><span class="status <?= $item['status']==='published'?'ok':'' ?>"><?= $item['status']==='published'?'Опубліковано':'Чернетка' ?></span></td><td><a class="forms-answer-count" href="<?= url('/admin/forms/submissions?form_id='.$item['id']) ?>"><span class="mdi mdi-inbox-outline"></span><?= e((string)$item['submissions_count']) ?></a></td><td><?= e((string)($item['last_submission_at']??'Ще немає')) ?></td><td><a class="button secondary compact" href="<?= url('/admin/forms/edit?id='.$item['id']) ?>"><span class="mdi mdi-pencil-outline"></span><span>Редагувати</span></a></td></tr><?php endforeach; ?>
</tbody></table></div><?php if(!$items): ?><div class="empty-state"><span class="mdi mdi-form-select"></span><h2>Створіть першу форму</h2><p>Додайте поля й опублікуйте форму на потрібній сторінці.</p><a class="button" href="<?= url('/admin/forms/edit') ?>">Створити форму</a></div><?php endif; ?></div>
